mapper.update:
UPDATE warning_record
SET status       = #{status},
    resolve_time = #{resolveTime},
    resolved_by  = #{resolvedBy}
WHERE id = #{id}

mapper.select:
SELECT w.id, w.reagent_id, w.reagent_name, w.reagent_batch, w.warning_type, w.trigger_time, w.status, w.resolve_time, w.resolved_by, r.safety_stock_threshold AS safetyStockThreshold, (SELECT COALESCE(SUM(rb.current_quantity), 0) FROM reagent_batch rb WHERE rb.reagent_id = w.reagent_id AND rb.status IN (0, 1)) AS currentStock FROM warning_record w LEFT JOIN reagent r ON w.reagent_id = r.id
AND w.status = #{status}
AND w.warning_type = #{warningType}
AND w.reagent_name LIKE CONCAT('%', #{reagentName}, '%')
ORDER BY w.trigger_time DESC
